#define INF 1<<28

#define F first

#define S second

using namespace std;



typedef pair < int, int > P;

vector < P > v[5];

int sx, sy, gx, gy;

int memo[5][5][1111];



int dist(P a, P b){

  return abs(a.F - b.F) + abs(a.S - b.S);

}





int solve(int cnt, int now, int idx){



  if(cnt == 4) return dist(v[now][idx], P(gx, gy));

  if(~memo[cnt][now][idx]) return memo[cnt][now][idx];



  int ans = INF, next = (now+1)%5, cost;

  for(int i=0;i<v[next].size();i++){

    cost = cnt?dist(v[now][idx], v[next][i]):dist(P(sx, sy), v[next][i]);

    ans = min(ans, solve(cnt+1, next, i) + cost);

  }



  return memo[cnt][now][idx] = ans;

}



int main(){



  int w, h;

  char c;



  while(scanf("%d %d", &w, &h), w){



    for(int i=0;i<5;i++) v[i].clear();



    for(int i=0;i<h;i++){

      for(int j=0;j<w;j++){

	scanf(" %c", &c);

	if(c == '.') continue;

	else if(c == 'S') sx = j, sy = i;

	else if(c == 'G') gx = j, gy = i;

	else v[c-'1'].push_back( P(j,i) );

      }

    }



    int a, b = INF;

    memset(memo, -1, sizeof(memo));

    for(int i=0;i<5;i++) if(b > solve(0,i,0)) a = i+1, b = solve(0,i,0);



    b == INF?puts("NA"):printf("%d %d\n", a, b);



  }

}

